using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design.
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch circle on the xz plane.
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr sketch = sketches->add(rootComp->xZConstructionPlane());
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchCirles = sketchCurves->sketchCircles();
    if (!sketchCirles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    Ptr sketchCircle = sketchCirles->addByCenterRadius(centerPoint, 3.0);
    if (!sketchCircle)
        return false;

    // Create a open profile for extrusion.
    Ptr openProfile = rootComp->createOpenProfile(sketchCircle);

    // Create an extrusion input.
    Ptr features = rootComp->features();
    if (!features)
        return false;
    Ptr extrudes = features->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extrudeInput =
        extrudes->createInput(openProfile, FeatureOperations::NewBodyFeatureOperation);
    if (!extrudeInput)
        return false;
    extrudeInput->isSolid(false);

    // Define the extent with a distance extent of 3 cm.
    Ptr distance = ValueInput::createByReal(3.0);
    if (!distance)
        return false;
    extrudeInput->setDistanceExtent(false, distance);

    // Create the extrusion.
    Ptr extrude = extrudes->add(extrudeInput);
    if (!extrude)
        return false;

    // Get the body created by extrusion.
    Ptr bodies = extrude->bodies();
    if (!bodies)
        return false;
    Ptr body = bodies->item(0);

    // Create sketch 2.
    Ptr sketch2 = sketches->add(rootComp->xYConstructionPlane());
    if (!sketch2)
        return false;
    Ptr sketchCurves2 = sketch2->sketchCurves();
    if (!sketchCurves2)
        return false;
    Ptr sketchLines = sketchCurves2->sketchLines();
    if (!sketchLines)
        return false;
    Ptr startPoint = Point3D::create(-5.0, 0, 0);
    Ptr endPoint = Point3D::create(5.0, 0, 0);
    Ptr sketchLine = sketchLines->addByTwoPoints(startPoint, endPoint);

    // Create a open profile.
    Ptr openProfile2 = rootComp->createOpenProfile(sketchLine);

    // Create an extrusion input.
    Ptr extrudeInput2 =
        extrudes->createInput(openProfile2, FeatureOperations::NewBodyFeatureOperation);
    if (!extrudeInput2)
        return false;
    extrudeInput2->isSolid(false);

    // Define the extent.
    Ptr distance2 = ValueInput::createByReal(5.0);
    extrudeInput2->setDistanceExtent(false, distance2);

    // Create the extrusion.
    extrudes->add(extrudeInput2);

    // Create trim feature.
    Ptr trims = features->trimFeatures();
    if (!trims)
        return false;
    Ptr trimInput = trims->createInput(body);
    if (!trimInput)
        return false;
    Ptr cells = trimInput->bRepCells();
    if (!cells)
        return false;
    Ptr cell = cells->item(0);
    if (!cell)
        return false;
    cell->isSelected(true);
    trims->add(trimInput);


    return true;
}
